ALTER TABLE "scenarios" ADD COLUMN "training_guide" jsonb;
CREATE TABLE "training_attempts" ("id" uuid PRIMARY KEY DEFAULT gen_random_uuid() NOT NULL,"user_id" uuid,"scenario_slug" text NOT NULL,"status" text DEFAULT 'in_progress' NOT NULL,"submission_id" uuid,"independence_score" double precision,"capability_scores" jsonb,"recommended_step_id" text,"created_at" timestamp with time zone DEFAULT now() NOT NULL,"updated_at" timestamp with time zone DEFAULT now() NOT NULL);
CREATE TABLE "training_step_answers" ("id" uuid PRIMARY KEY DEFAULT gen_random_uuid() NOT NULL,"attempt_id" uuid NOT NULL,"step_id" text NOT NULL,"revision" integer DEFAULT 1 NOT NULL,"answer" text DEFAULT '' NOT NULL,"hint_level" integer DEFAULT 0 NOT NULL,"follow_up_question" text,"follow_up_answer" text,"created_at" timestamp with time zone DEFAULT now() NOT NULL,"updated_at" timestamp with time zone DEFAULT now() NOT NULL);
ALTER TABLE "training_attempts" ADD CONSTRAINT "training_attempts_user_id_users_id_fk" FOREIGN KEY ("user_id") REFERENCES "public"."users"("id") ON DELETE cascade;
ALTER TABLE "training_attempts" ADD CONSTRAINT "training_attempts_submission_id_submissions_id_fk" FOREIGN KEY ("submission_id") REFERENCES "public"."submissions"("id") ON DELETE set null;
ALTER TABLE "training_step_answers" ADD CONSTRAINT "training_step_answers_attempt_id_training_attempts_id_fk" FOREIGN KEY ("attempt_id") REFERENCES "public"."training_attempts"("id") ON DELETE cascade;
CREATE INDEX "idx_training_attempts_user" ON "training_attempts" ("user_id"); CREATE INDEX "idx_training_attempts_scenario" ON "training_attempts" ("scenario_slug"); CREATE UNIQUE INDEX "uq_training_step_revision" ON "training_step_answers" ("attempt_id","step_id","revision"); CREATE INDEX "idx_training_answers_attempt" ON "training_step_answers" ("attempt_id");
